defmodule WebhookProxyController do
  use Phoenix.Controller

  @allowed_hosts ~w[api.example.com webhook.example.com]
  @max_redirects 3

  def fetch(conn, %{"url" => url}) do
    case URI.parse(url) do
      %URI{host: nil} ->
        conn
        |> put_status(400)
        |> json(%{error: "Invalid URL"})

      %URI{host: host} when host in @allowed_hosts ->
        case fetch_url(url) do
          {:ok, response} ->
            conn
            |> put_status(response.status_code)
            |> put_resp_header("content-type", response.headers["content-type"])
            |> send_resp(response.status_code, response.body)

          {:error, reason} ->
            conn
            |> put_status(500)
            |> json(%{error: "Failed to fetch URL", reason: reason})
        end

      _ ->
        conn
        |> put_status(400)
        |> json(%{error: "Host not allowed"})
    end
